noncompliant:
// Noncompliant: backward jump creating a loop
void function() {
    int i = 0;

    loop_start:  // Label declared before goto
        printf("i = %d\n", i);
        i++;
        if (i < 10) {
            goto loop_start;  // Noncompliant: jumping backward
        }
}

// Noncompliant: jumping to previously declared label
void processData() {
    retry:
        // some processing

    if (someCondition()) {
        goto retry;  // Noncompliant: backward jump
    }
}

compliant:
// Compliant: forward jump to later declared label
void function() {
    if (error_condition) {
        goto cleanup;  // Forward jump to label declared later
    }

    // normal processing

    cleanup:
        // cleanup code
}

// Compliant: using proper loop construct instead
void function() {
    for (int i = 0; i < 10; i++) {
        printf("i = %d\n", i);  // Proper loop instead of goto
    }
}
